#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <cuda_runtime.h>

#include "./../main.h"
#include "./../util/avi/avilib.h"
#include "./../util/avi/avimod.h"

// Removed include of missing header "./kernel_gpu_opencl_wrapper.h"

extern int platform_id_inuse;
extern int device_id_inuse;

void 
kernel_gpu_opencl_wrapper(	params_common common,
							int* endoRow,
							int* endoCol,
							int* tEndoRowLoc,
							int* tEndoColLoc,
							int* epiRow,
							int* epiCol,
							int* tEpiRowLoc,
							int* tEpiColLoc,
							avi_t* frames)
{
	int i;

	int error;

	int num_devices;
	cudaGetDeviceCount(&num_devices);
	printf("# of devices %d\n", num_devices);

	int devi = device_id_inuse;
	cudaSetDevice(devi);
	printf("Selecting device %d\n", devi);

	// Allocate device memory
	params_common* d_common;
	cudaMalloc((void**)&d_common, sizeof(params_common));
	cudaMemcpy(d_common, &common, sizeof(params_common), cudaMemcpyHostToDevice);

	fp* d_frame;
	cudaMalloc((void**)&d_frame, common.frame_mem);

	int* d_endoRow;
	cudaMalloc((void**)&d_endoRow, common.endo_mem);
	cudaMemcpy(d_endoRow, endoRow, common.endo_mem, cudaMemcpyHostToDevice);

	int* d_endoCol;
	cudaMalloc((void**)&d_endoCol, common.endo_mem);
	cudaMemcpy(d_endoCol, endoCol, common.endo_mem, cudaMemcpyHostToDevice);

	int* d_tEndoRowLoc;
	cudaMalloc((void**)&d_tEndoRowLoc, common.endo_mem * common.no_frames);

	int* d_tEndoColLoc;
	cudaMalloc((void**)&d_tEndoColLoc, common.endo_mem * common.no_frames);

	int* d_epiRow;
	cudaMalloc((void**)&d_epiRow, common.epi_mem);
	cudaMemcpy(d_epiRow, epiRow, common.epi_mem, cudaMemcpyHostToDevice);

	int* d_epiCol;
	cudaMalloc((void**)&d_epiCol, common.epi_mem);
	cudaMemcpy(d_epiCol, epiCol, common.epi_mem, cudaMemcpyHostToDevice);

	int* d_tEpiRowLoc;
	cudaMalloc((void**)&d_tEpiRowLoc, common.epi_mem * common.no_frames);

	int* d_tEpiColLoc;
	cudaMalloc((void**)&d_tEpiColLoc, common.epi_mem * common.no_frames);

	fp* d_endoT;
	cudaMalloc((void**)&d_endoT, common.in_mem * common.endoPoints);

	fp* d_epiT;
	cudaMalloc((void**)&d_epiT, common.in_mem * common.epiPoints);

	fp* d_in2_all;
	cudaMalloc((void**)&d_in2_all, common.in2_mem * common.allPoints);

	fp* d_conv_all;
	cudaMalloc((void**)&d_conv_all, common.conv_mem * common.allPoints);

	fp* d_in2_pad_cumv_all;
	cudaMalloc((void**)&d_in2_pad_cumv_all, common.in2_pad_cumv_mem * common.allPoints);

	fp* d_in2_pad_cumv_sel_all;
	cudaMalloc((void**)&d_in2_pad_cumv_sel_all, common.in2_pad_cumv_sel_mem * common.allPoints);

	fp* d_in2_sub_cumh_all;
	cudaMalloc((void**)&d_in2_sub_cumh_all, common.in2_sub_cumh_mem * common.allPoints);

	fp* d_in2_sub_cumh_sel_all;
	cudaMalloc((void**)&d_in2_sub_cumh_sel_all, common.in2_sub_cumh_sel_mem * common.allPoints);

	fp* d_in2_sub2_all;
	cudaMalloc((void**)&d_in2_sub2_all, common.in2_sub2_mem * common.allPoints);

	fp* d_in2_sqr_all;
	cudaMalloc((void**)&d_in2_sqr_all, common.in2_sqr_mem * common.allPoints);

	fp* d_in2_sqr_sub2_all;
	cudaMalloc((void**)&d_in2_sqr_sub2_all, common.in2_sqr_sub2_mem * common.allPoints);

	fp* d_in_sqr_all;
	cudaMalloc((void**)&d_in_sqr_all, common.in_sqr_mem * common.allPoints);

	fp* d_tMask_all;
	cudaMalloc((void**)&d_tMask_all, common.tMask_mem * common.allPoints);

	fp* d_mask_conv_all;
	cudaMalloc((void**)&d_mask_conv_all, common.mask_conv_mem * common.allPoints);

	fp* d_in_mod_temp_all;
	cudaMalloc((void**)&d_in_mod_temp_all, sizeof(fp) * common.in_elem * common.allPoints);

	fp* in_partial_sum_all;
	cudaMalloc((void**)&in_partial_sum_all, sizeof(fp) * common.in_cols * common.allPoints);

	fp* in_sqr_partial_sum_all;
	cudaMalloc((void**)&in_sqr_partial_sum_all, sizeof(fp) * common.in_sqr_rows * common.allPoints);

	fp* par_max_val_all;
	cudaMalloc((void**)&par_max_val_all, sizeof(fp) * common.mask_conv_rows * common.allPoints);

	int* par_max_coo_all;
	cudaMalloc((void**)&par_max_coo_all, sizeof(int) * common.mask_conv_rows * common.allPoints);

	fp* in_final_sum_all;
	cudaMalloc((void**)&in_final_sum_all, sizeof(fp) * common.allPoints);

	fp* in_sqr_final_sum_all;
	cudaMalloc((void**)&in_sqr_final_sum_all, sizeof(fp) * common.allPoints);

	fp* denomT_all;
	cudaMalloc((void**)&denomT_all, sizeof(fp) * common.allPoints);

	fp* d_checksum;
	cudaMalloc((void**)&d_checksum, sizeof(fp) * CHECK);

	printf("tSize is %d, sSize is %d\n", common.tSize, common.sSize);
	common.in_rows = common.tSize + 1 + common.tSize;
	common.in_cols = common.in_rows;
	common.in_elem = common.in_rows * common.in_cols;
	common.in_mem = sizeof(fp) * common.in_elem;

	size_t local_work_size = NUMBER_THREADS;
	size_t global_work_size = common.allPoints * local_work_size;

	printf("# of workgroups = %zu, # of threads/workgroup = %zu (ensure that device can handle)\n", global_work_size/local_work_size, local_work_size);

	for(int frame_no=0; frame_no<common.frames_processed; frame_no++){

		fp* frame = get_frame(frames, frame_no, 0, 0, 1);

		cudaMemcpy(d_frame, frame, common.frame_mem, cudaMemcpyHostToDevice);
		free(frame);

		kernel_gpu_opencl<<<common.allPoints, NUMBER_THREADS>>>(common,
			d_frame,
			frame_no,
			d_endoRow,
			d_endoCol,
			d_tEndoRowLoc,
			d_tEndoColLoc,
			d_epiRow,
			d_epiCol,
			d_tEpiRowLoc,
			d_tEpiColLoc,
			d_endoT,
			d_epiT,
			d_in2_all,
			d_conv_all,
			d_in2_pad_cumv_all,
			d_in2_pad_cumv_sel_all,
			d_in2_sub_cumh_all,
			d_in2_sub_cumh_sel_all,
			d_in2_sub2_all,
			d_in2_sqr_all,
			d_in2_sqr_sub2_all,
			d_in_sqr_all,
			d_tMask_all,
			d_mask_conv_all,
			d_in_mod_temp_all,
			in_partial_sum_all,
			in_sqr_partial_sum_all,
			par_max_val_all,
			par_max_coo_all,
			in_final_sum_all,
			in_sqr_final_sum_all,
			denomT_all,
			d_checksum);

		cudaDeviceSynchronize();

#ifdef TEST_CHECKSUM
		fp* checksum = (fp*)malloc(sizeof(fp) * CHECK);
		cudaMemcpy(checksum, d_checksum, sizeof(fp)*CHECK, cudaMemcpyDeviceToHost);
		printf("CHECKSUM:\n");
		for(i=0; i<CHECK; i++){
			printf("%f ", checksum[i]);
		}
		printf("\n\n");
		free(checksum);
#endif

		printf("%d ", frame_no);
		fflush(NULL);
	}

	printf("\n");
	fflush(NULL);

	cudaMemcpy(tEndoRowLoc, d_tEndoRowLoc, common.endo_mem * common.no_frames, cudaMemcpyDeviceToHost);
	cudaMemcpy(tEndoColLoc, d_tEndoColLoc, common.endo_mem * common.no_frames, cudaMemcpyDeviceToHost);
	cudaMemcpy(tEpiRowLoc, d_tEpiRowLoc, common.epi_mem * common.no_frames, cudaMemcpyDeviceToHost);
	cudaMemcpy(tEpiColLoc, d_tEpiColLoc, common.epi_mem * common.no_frames, cudaMemcpyDeviceToHost);

	cudaFree(d_frame);
	cudaFree(d_endoRow);
	cudaFree(d_endoCol);
	cudaFree(d_tEndoRowLoc);
	cudaFree(d_tEndoColLoc);
	cudaFree(d_epiRow);
	cudaFree(d_epiCol);
	cudaFree(d_tEpiRowLoc);
	cudaFree(d_tEpiColLoc);
	cudaFree(d_endoT);
	cudaFree(d_epiT);
	cudaFree(d_in2_all);
	cudaFree(d_conv_all);
	cudaFree(d_in2_pad_cumv_all);
	cudaFree(d_in2_pad_cumv_sel_all);
	cudaFree(d_in2_sub_cumh_all);
	cudaFree(d_in2_sub_cumh_sel_all);
	cudaFree(d_in2_sub2_all);
	cudaFree(d_in2_sqr_all);
	cudaFree(d_in2_sqr_sub2_all);
	cudaFree(d_in_sqr_all);
	cudaFree(d_tMask_all);
	cudaFree(d_mask_conv_all);
	cudaFree(d_in_mod_temp_all);
	cudaFree(in_partial_sum_all);
	cudaFree(in_sqr_partial_sum_all);
	cudaFree(par_max_val_all);
	cudaFree(par_max_coo_all);
	cudaFree(in_final_sum_all);
	cudaFree(in_sqr_final_sum_all);
	cudaFree(denomT_all);
	cudaFree(d_checksum);
	cudaFree(d_common);
}
